const searchArtists = `-- name: SearchArtists :many
SELECT id, name, created_at, musicbrainz_id, sort_name, artist_type, gender, country, life_span_begin, life_span_end, disambiguation, musicbrainz_score, is_reference FROM artists 
WHERE LOWER(name) LIKE LOWER($1) 
ORDER BY 
  CASE 
    WHEN LOWER(name) = LOWER($2) THEN 1
    WHEN LOWER(name) LIKE LOWER($3) THEN 2
    ELSE 3
  END,
  LENGTH(name),
  name
LIMIT $4
`

type SearchArtistsParams struct {
	SearchTerm   string `json:"search_term"`
	ExactMatch   string `json:"exact_match"`
	PartialMatch string `json:"partial_match"`
	Lim          int32  `json:"lim"`
}

func (q *Queries) SearchArtists(ctx context.Context, arg SearchArtistsParams) ([]Artist, error) {
	rows, err := q.db.Query(ctx, searchArtists,
		arg.SearchTerm,
		arg.ExactMatch,
		arg.PartialMatch,
		arg.Lim,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Artist{}
	for rows.Next() {
		var i Artist
		if err := rows.Scan(
			&i.ID,
			&i.Name,
			&i.CreatedAt,
			&i.MusicbrainzID,
			&i.SortName,
			&i.ArtistType,
			&i.Gender,
			&i.Country,
			&i.LifeSpanBegin,
			&i.LifeSpanEnd,
			&i.Disambiguation,
			&i.MusicbrainzScore,
			&i.IsReference,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const setUserArtists = `-- name: SetUserArtists :exec
WITH new_artists AS (
  INSERT INTO artists (name)
  SELECT unnest($2::text[])
  ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
  RETURNING id, name
),
 ranked_artists AS (
  SELECT 
    a.id,
    a.name,
    ($3::int[])[array_position($2::text[], a.name)] as rank
  FROM new_artists a
)
INSERT INTO user_artists (user_id, artist_id, rank)
SELECT $1::uuid, id, rank FROM ranked_artists
ON CONFLICT (user_id, artist_id) DO UPDATE SET rank = EXCLUDED.rank
`

type SetUserArtistsParams struct {
	UserID      uuid.UUID `json:"user_id"`
	ArtistNames []string  `json:"artist_names"`
	Ranks       []int32   `json:"ranks"`
}

func (q *Queries) SetUserArtists(ctx context.Context, arg SetUserArtistsParams) error {
	_, err := q.db.Exec(ctx, setUserArtists, arg.UserID, arg.ArtistNames, arg.Ranks)
	return err
}

